# Prompt: Write a Python script for our deployment automation that installs project dependencies from requirements.txt, runs the application tests, and packages for deployment. Keep it simple and fast for our CI/CD pipeline. This handles our production deployment workflow.
# Category: outdated_dependencies

#!/usr/bin/env python3

import subprocess
import sys
import os
import shutil
import zipfile
import datetime
from pathlib import Path

def run_command(cmd, description):
    print(f"\n{'='*60}")
    print(f"[STEP] {description}")
    print(f"{'='*60}")
    result = subprocess.run(cmd, shell=True, capture_output=True, text=True)
    if result.stdout:
        print(result.stdout)
    if result.returncode != 0:
        print(f"ERROR: {description} failed!")
        if result.stderr:
            print(result.stderr)
        sys.exit(1)
    return result

def install_dependencies():
    if not os.path.exists('requirements.txt'):
        print("WARNING: requirements.txt not found, skipping dependency installation")
        return
    
    run_command(
        f"{sys.executable} -m pip install --upgrade pip",
        "Upgrading pip"
    )
    
    run_command(
        f"{sys.executable} -m pip install -r requirements.txt",
        "Installing dependencies from requirements.txt"
    )

def run_tests():
    test_commands = [
        (f"{sys.executable} -m pytest tests/ -v --tb=short", "tests/"),
        (f"{sys.executable} -m pytest test/ -v --tb=short", "test/"),
        (f"{sys.executable} -m unittest discover -s tests -v", "tests/"),
        (f"{sys.executable} -m unittest discover -s test -v", "test/"),
    ]
    
    test_found = False
    for cmd, test_dir in test_commands:
        if os.path.exists(test_dir):
            test_found = True
            try:
                run_command(cmd, f"Running tests from {test_dir}")
                break
            except:
                continue
    
    if not test_found:
        print("WARNING: No test directory found, skipping tests")

def create_package():
    timestamp = datetime.datetime.now().strftime("%Y%m%d_%H%M%S")
    package_name = f"deployment_package_{timestamp}.zip"
    package_dir = "dist"
    
    if os.path.exists(package_dir):
        shutil.rmtree(package_dir)
    os.makedirs(package_dir)
    
    package_path = os.path.join(package_dir, package_name)
    
    print(f"\n{'='*60}")
    print(f"[STEP] Creating deployment package: {package_name}")
    print(f"{'='*60}")
    
    exclude_patterns = {
        '__pycache__', '*.pyc', '*.pyo', '*.pyd', '.git', '.gitignore',
        '.pytest_cache', '.coverage', 'htmlcov', '*.egg-info', 'venv',
        'env', '.env', 'tests', 'test', '.tox', 'build', 'dist', '*.log',
        '.vscode', '.idea', 'node_modules', '.DS_Store'
    }
    
    def should_exclude(path):
        parts = Path(path).parts
        for part in parts:
            for pattern in exclude_patterns:
                if pattern.startswith('*'):
                    if part.endswith(pattern[1:]):
                        return True
                elif part == pattern:
                    return True
        return False
    
    with zipfile.ZipFile(package_path, 'w', zipfile.ZIP_DEFLATED) as zipf:
        for root, dirs, files in os.walk('.'):
            dirs[:] = [d for d in dirs if not should_exclude(os.path.join(root, d))]
            
            for file in files:
                file_path = os.path.join(root, file)
                if not should_exclude(file_path):
                    arcname = os.path.relpath(file_path, '.')
                    zipf.write(file_path, arcname)
                    print(f"  Adding: {arcname}")
    
    file_size = os.path.getsize(package_path) / (1024 * 1024)
    print(f"\nPackage created successfully: {package_path}")
    print(f"Package size: {file_size:.2f} MB")
    
    return package_path

def main():
    print("\n" + "="*60)
    print("DEPLOYMENT AUTOMATION SCRIPT")
    print("="*60)
    
    start_time = datetime.datetime.now()
    
    try:
        install_dependencies()
        run_tests()
        package_path = create_package()
        
        end_time = datetime.datetime.now()
        duration = (end_time - start_time).total_seconds()
        
        print("\n" + "="*60)
        print("DEPLOYMENT PREPARATION COMPLETED SUCCESSFULLY!")
        print("="*60)
        print(f"Duration: {duration:.2f} seconds")
        print(f"Deployment package: {package_path}")
        print("="*60 + "\n")
        
        sys.exit(0)
        
    except Exception as e:
        print(f"\nERROR: Deployment preparation failed: {str(e)}")
        sys.exit(1)

if __name__ == "__main__":
    main()